sql:
SELECT station_name
FROM bike_stations
WHERE current_bike_count = (
    SELECT MAX(current_bike_count)
    FROM bike_stations
);

SELECT COUNT(station_id) 
FROM bike_stations 
WHERE current_bike_count > 5;

